  const BOSS_GATE_PLAN = [
    {gate:1, after:[1,2,3], title:'Boss Gate 1: Foundation Check', focus:'Reading main idea + short writing + listening prompt + speaking goal', skills:['Reading','Writing','Listening','Speaking'], type:'major'},
    {gate:2, after:[4,5,6], title:'Boss Gate 2: Critical Reading & Summary Check', focus:'keywords/signal words, bias awareness, summary, short oral summary', skills:['Reading','Writing','Listening','Speaking'], type:'major'},
    {gate:3, after:[7,8,9], title:'Boss Gate 3: Academic Paragraph Check', focus:'academic tone, paragraph structure, paragraph writing, oral explanation', skills:['Reading','Writing','Listening','Speaking'], type:'major'},
    {gate:4, after:[10,11,12], title:'Boss Gate 4: Data / Email / Ethics Check', focus:'data description, academic email, paraphrase/citation ethics, polite request', skills:['Reading','Writing','Listening','Speaking'], type:'major'},
    {gate:5, after:[13,14,15], title:'Final Boss: Integrated EAP Performance', focus:'mini lecture notes, presentation, final integrated response and reflection', skills:['Reading','Writing','Listening','Speaking'], type:'final'}
  ];

  function bossGateForSession(sessionId){
    const sid = Number(sessionId || 1);
    return BOSS_GATE_PLAN.find(g => g.after.includes(sid)) || BOSS_GATE_PLAN[0];
  }
  function bossGateAfterSession(sessionId){
    const sid = Number(sessionId || 1);
    return BOSS_GATE_PLAN.find(g => g.after[g.after.length - 1] === sid) || null;
  }
  function bossGateByNumber(gateNo){
    return BOSS_GATE_PLAN.find(g => Number(g.gate) === Number(gateNo)) || BOSS_GATE_PLAN[0];
  }
  function isBossGateUnlocked(gateNo){
    return bossGateUnlockReport(gateNo).unlocked;
  }



  function deepTextOfEvidenceItem(item){
    try{
      if(item == null) return '';
      if(typeof item === 'string') return item;
      return JSON.stringify(item);
    }catch(e){
      return String(item || '');
    }
  }

  function extractSessionIdFromEvidence(item){
    const direct = Number(item?.sessionId || item?.session || item?.s || item?.sid || item?.currentSession || item?.sessionNo || item?.sessionNumber || 0);
    if(direct) return direct;
    const txt = deepTextOfEvidenceItem(item);
    const m = txt.match(/Session\s*[:#-]?\s*(\d{1,2})|S(\d{1,2})\b/i);
    if(m) return Number(m[1] || m[2] || 0);
    return 0;
  }

  function extractSkillFromEvidence(item){
    const direct = String(item?.skill || item?.type || item?.missionSkill || item?.category || item?.mode || '').toLowerCase();
    const txt = (direct + ' ' + deepTextOfEvidenceItem(item).toLowerCase());
    if(txt.includes('reading')) return 'Reading';
    if(txt.includes('writing')) return 'Writing';
    if(txt.includes('listening')) return 'Listening';
    if(txt.includes('speaking')) return 'Speaking';
    return '';
  }

  function extractScoreFromEvidence(item){
    const direct = Number(item?.score || item?.autoScore || item?.percent || item?.points || item?.grade || item?.resultScore || 0);
    if(direct) return direct;
    const txt = deepTextOfEvidenceItem(item);
    const m = txt.match(/(\d{1,3})\s*\/\s*100|score["']?\s*[:=]\s*(\d{1,3})|autoScore["']?\s*[:=]\s*(\d{1,3})/i);
    if(m) return Number(m[1] || m[2] || m[3] || 0);
    return 0;
  }

  function allEvidenceItems(){
    const out = [];
    const buckets = [
      state.portfolio,
      state.learningReports,
      state.reports,
      state.evidence,
      state.submissions,
      state.logs,
      state.skillEvidence,
      state.missionEvidence,
      state.rubricReviews
    ];
    buckets.forEach(bucket=>{
      if(!bucket) return;
      if(Array.isArray(bucket)) out.push(...bucket);
      else if(typeof bucket === 'object') out.push(...Object.values(bucket));
    });
    return out;
  }

  function sessionEvidenceSummary(sessionId){
    const sid = Number(sessionId || 1);
    const skills = new Set();
    let bestScore = 0;
    const items = [];
    allEvidenceItems().forEach(item=>{
      const itemSid = extractSessionIdFromEvidence(item);
      if(itemSid !== sid) return;
      const sk = extractSkillFromEvidence(item);
      if(sk) skills.add(sk);
      const score = extractScoreFromEvidence(item);
      if(score > bestScore) bestScore = score;
      items.push(item);
    });

    const sess = state.sessions?.[sid] || {};
    const skillObj = sess.skills || sess.skillDone || sess.skillProgress || sess.missions || {};
    ['Reading','Writing','Listening','Speaking'].forEach(k=>{
      if(skillObj[k] || skillObj[k.toLowerCase()] || skillObj[k.toUpperCase()]) skills.add(k);
    });

    if(state.bossCards?.[sid]) bestScore = Math.max(bestScore, 80);
    const count = skills.size || items.length;
    const stars = bestScore >= 90 ? 3 : bestScore >= 75 ? 2 : bestScore >= 60 ? 1 : count >= 2 ? 1 : 0;
    return {session:sid, skills:Array.from(skills), count, items:items.length, bestScore, stars};
  }

  function earnedStarsHTML(sessionId){
    const st = sessionStarScore(sessionId);
    return `<span class="earned-stars ${st.stars ? 'has-stars':'no-stars'}">${sessionStarsText(sessionId)}</span>`;
  }

  function sessionProgressBadgeHTML(sessionId){
    const st = sessionStarScore(sessionId);
    return `<div class="session-progress-badge ${st.passed?'complete':'needs'}">
      ${st.passed?'✅ Passed':'⚠️ Not yet'} · avg ${st.avg || 0} · ${sessionStarsText(sessionId)}
    </div>`;
  }

  function augmentSessionCardsWithProgress(){
    try{
      document.querySelectorAll('.session-progress-badge').forEach(x=>x.remove());
      document.querySelectorAll('.map-card,.session-card,[data-session-card]').forEach(card=>{
        if(!card || card.closest('.black-screen-recovery')) return;
        const txt = (card.textContent || '');
        const mm = txt.match(/SESSION\s+(\d{1,2})\b|S(\d{1,2})\b/i);
        if(!mm) return;
        const sid = Number(mm[1] || mm[2] || 0);
        if(!sid || sid < 1 || sid > 15) return;
        if(card.querySelector('.session-progress-badge')) return;
        card.insertAdjacentHTML('beforeend', sessionProgressBadgeHTML(sid));
      });
    }catch(err){
      console.warn('[augmentSessionCardsWithProgress]', err);
      logRuntimeErrorSafe('augmentSessionCardsWithProgress', err);
    }
  }

  function runSessionEvidenceSyncSoon(){
    augmentSessionCardsWithProgress();
    setTimeout(augmentSessionCardsWithProgress, 0);
    setTimeout(augmentSessionCardsWithProgress, 180);
  }


  function skillEvidenceCountForSession(sessionId){
    const e = sessionEvidenceSummary(sessionId);
    return {count:e.count, skills:e.skills};
  }

  function sessionCompletionReport(sessionId){
    const rep = sessionPassReport(sessionId);
    const ev = typeof sessionEvidenceSummary === 'function' ? sessionEvidenceSummary(sessionId) : {skills:[],count:0,items:0,bestScore:0,stars:0};
    return {session:rep.session, complete:rep.passed, explicit:rep.explicit, cardLike:!!state.bossCards?.[rep.session], evidenceSkills:ev.skills || rep.requiredSkills, evidenceCount:ev.count || rep.skillRows.filter(x=>x.items).length, evidenceItems:ev.items || 0, bestScore:Math.max(ev.bestScore || 0, ...rep.skillRows.map(x=>x.bestScore || 0)), stars:ev.stars || 0, reason:rep.reason};
  }


  function isSessionCompleteForGate(sessionId){
    return sessionCompletionReport(sessionId).complete;
  }

  function isPreviousBossGateCleared(gateNo){
    const n = Number(gateNo || 1);
    if(n <= 1) return true;
    const prev = state.bossGates?.[n-1] || {};
    return !!(prev.cleared || prev.done || prev.completed);
  }

  function bossGateUnlockReport(gateNo){
    const g = bossGatePassStatus(gateNo);
    return {gate:g.gate, title:g.title, sessions:g.sessions.map(r=>r.session), sessionReports:g.sessions.map(r=>({session:r.session, complete:r.passed, reason:r.reason, evidenceSkills:r.requiredSkills, evidenceCount:r.skillRows.filter(x=>x.passed).length})), missingSessions:g.sessions.filter(r=>!r.passed).map(r=>r.session), missingDetail:g.missing.join(' | '), previousGateRequired:g.gate > 1 ? g.gate - 1 : null, previousGateCleared:g.previousGateCleared, unlocked:g.unlocked, reason:g.unlocked ? 'Unlocked' : g.missing.join(' ')};
  }

  function bossGateLockMessage(gateNo){
    const r = bossGateUnlockReport(gateNo);
    const details = (r.sessionReports || []).map(x=>`<li>${x.complete?'✅':'⚠️'} S${x.session}: ${safe(x.reason)}${x.evidenceSkills?.length ? ' — '+safe(x.evidenceSkills.join(', ')) : ''}</li>`).join('');
    return `<div class="boss-gate-lock-message">
      <h3>🔒 ${safe(r.title)} is locked</h3>
      <p>${safe(bossGateUnlockRuleText(r.gate))}</p><p>${safe(r.reason || 'Complete the required sessions first.')}</p>
      <p><b>Required route:</b> ${r.sessions.map(s=>'S'+s).join(' → ')} → ${safe(r.title)}</p>
      ${r.previousGateRequired ? `<p><b>Also required:</b> Clear Boss Gate ${r.previousGateRequired}</p>` : ''}
      <ul class="gate-session-checklist">${details}</ul>
      <div class="footer-actions">
        <button class="btn primary" onclick="EAPHero.map()">Back to Map</button>
        <button class="btn" onclick="EAPHero.continueSession()">Continue Session</button>
      </div>
    </div>`;
  }


  function repairLegacySessionCompletion(){
    state.sessions = state.sessions || {};
    for(let sid=1; sid<=15; sid++){
      const rep = sessionCompletionReport(sid);
      const ev = sessionEvidenceSummary(sid);
      state.sessions[sid] = state.sessions[sid] || {};
      state.sessions[sid].earnedStars = ev.stars;
      state.sessions[sid].evidenceCount = ev.count;
      state.sessions[sid].evidenceSkills = ev.skills;
      if(rep.complete){
        state.sessions[sid].completed = true;
        state.sessions[sid].completionReason = rep.reason;
      }
    }
    saveState();
    safeToast('Session evidence and stars synced');
    renderMap();
  }


  function renderBossGateLocked(gateNo){
    layout(`<section class="panel" style="margin-top:20px">${bossGateLockMessage(gateNo)}</section>`);
  }


  function bossGateProgress(){
    const cleared = BOSS_GATE_PLAN.filter(g => state.bossGates?.[g.gate]?.cleared || state.bossGates?.[g.gate]?.done).length;
    return {cleared, total:BOSS_GATE_PLAN.length};
  }
  function sessionBossProgress(){
    return {cleared:Object.keys(state.bossCards || {}).length, total:15};
  }


  function bossGateShortLabel(gateNo){
    const gate = bossGateByNumber(gateNo);
    return gate.type === 'final' ? 'Final Boss' : `Boss Gate ${gate.gate}`;
  }

  function bossGateUnlockRuleText(gateNo){
    const gate = bossGateByNumber(gateNo);
    const route = gate.after.map(s=>'S'+s).join(' + ');
    if(gate.gate === 1) return `Pass ${route} to unlock Boss Gate 1.`;
    if(gate.type === 'final') return `Pass ${route} and clear Boss Gate 4 to unlock Final Boss.`;
    return `Pass ${route} and clear Boss Gate ${gate.gate - 1} to unlock Boss Gate ${gate.gate}.`;
  }

  function sessionIsNotBossNote(sessionId){
    const sid = Number(sessionId || 1);
    const gate = bossGateAfterSession(sid);
    if(!gate) return '';
    return `<div class="session-not-boss-note">
      <b>S${sid} is still a normal Session.</b>
      <span>${bossGateShortLabel(gate.gate)} opens only after the required sessions are complete. ${safe(bossGateUnlockRuleText(gate.gate))}</span>
    </div>`;
  }

