  function skillPathForSession(sessionId){
    const m = finalMatrixForSession(sessionId);
    return { core:m.core, support:m.support, optional:m.optional || [] };
  }



  function openSkillMissionFromButton(btn){
    const skill = btn?.dataset?.skill || btn?.getAttribute?.('data-skill') || '';
    const sessionId = btn?.dataset?.session || btn?.getAttribute?.('data-session') || 1;
    openSkillMission(skill, sessionId);
    return false;
  }

  function bindHardButtonDelegation(){
    if(window.__EAP_HARD_BINDING__) return;
    window.__EAP_HARD_BINDING__ = true;
    document.addEventListener('click', function(ev){
      const btn = ev.target && ev.target.closest ? ev.target.closest('.js-skill-mission-btn') : null;
      if(!btn) return;
      ev.preventDefault();
      ev.stopPropagation();
      openSkillMissionFromButton(btn);
    }, true);
  }


  function openSkillMission(skill, sessionId){
    sessionId = Number(sessionId || 1);
    const rawSkill = String(skill || '').trim();
    const k = rawSkill.toLowerCase();
    try{
      const routes = {
        reading: renderReadingMission,
        writing: renderWritingMission,
        listening: renderListeningMission,
        speaking: renderSpeakingMission
      };
      const fn = routes[k];
      if(typeof fn === 'function'){
        fn(sessionId);
        return false;
      }
      const api = window.EAPHero || {};
      const apiFn = api[`${k}Mission`];
      if(typeof apiFn === 'function'){
        apiFn(sessionId);
        return false;
      }
      safeToast(`Skill mission not found: ${rawSkill}`);
      renderSkillPath(sessionId);
      return false;
    }catch(err){
      console.error('[EAP openSkillMission]', err);
      state.runtimeErrors = state.runtimeErrors || [];
      state.runtimeErrors.push({at:new Date().toISOString(), message:String(err.message || err), source:'openSkillMission', skill:rawSkill, sessionId});
      saveState();
      alert('Mission could not open. Error: ' + (err.message || err));
      renderSkillPath(sessionId);
      return false;
    }
  }



  function logRuntimeErrorSafe(source, err, extra){
    try{
      state.runtimeErrors = state.runtimeErrors || [];
      state.runtimeErrors.push({
        at:new Date().toISOString(),
        source:source || 'runtime',
        message:String(err?.message || err),
        stack:String(err?.stack || '').slice(0,1200),
        extra:extra || null,
        view:state.view || ''
      });
      saveState();
    }catch(e){}
  }

  function renderSessionRecoveryPanel(sessionId, err, source){
    const sid = Number(sessionId || state.currentSession || 1) || 1;
    const msg = String(err?.message || err || 'Unknown render error');
    try{
      layout(`<section class="panel black-screen-recovery" style="margin-top:20px">
        <div class="badges"><span class="pill">Recovery Mode</span><span class="pill">S${sid}</span><span class="pill">v1z44</span></div>
        <h2>Session could not open safely</h2>
        <p class="lead">ระบบกันจอดำเปิดทำงานแล้ว หน้านี้ช่วยกลับไปเล่นต่อได้โดยไม่ค้าง</p>
        <div class="recovery-error">
          <b>Error source:</b> ${safe(source || 'session render')}<br>
          <b>Message:</b> ${safe(msg)}
        </div>
        <div class="footer-actions">
          <button class="btn primary" onclick="EAPHero.map()">Back to Map</button>
          <button class="btn" onclick="return EAPHero.directOpenSession(${sid})">Try Again</button>
          <button class="btn" onclick="EAPHero.repairLegacySessionCompletion()">Repair Progress</button>
          <button class="btn ghost" onclick="EAPHero.continueSession()">Continue</button>
        </div>
      </section>`);
    }catch(e){
      const el = document.getElementById('app') || document.body;
      el.innerHTML = `<div style="margin:24px;padding:20px;border-radius:18px;background:#fff;color:#111;font-family:system-ui">
        <h2>Recovery Mode</h2>
        <p>Session S${sid} could not render.</p>
        <pre>${safe(msg)}</pre>
        <button onclick="EAPHero.map()">Back to Map</button>
      </div>`;
    }
  }



  function safeSessionMeta(sessionId){
    const sid = Number(sessionId || state.currentSession || 1) || 1;
    let s = null;
    try{ s = typeof getSession === 'function' ? getSession(sid) : null; }catch(e){}
    if(!s && Array.isArray(SESSIONS)) s = SESSIONS.find(x=>Number(x.id)===sid);
    if(!s) s = {id:sid, title:`Session ${sid}`, boss:'Session Boss', skill:'Academic English', subtitle:'Skill practice'};
    return s;
  }


  function checkpointSessionNoteHTML(sessionId){
    return compactCheckpointNoteHTML(sessionId);
  }


  function compactCheckpointNoteHTML(sessionId){
    const sid = Number(sessionId || state.currentSession || 1) || 1;
    const gate = typeof bossGateAfterSession === 'function' ? bossGateAfterSession(sid) : null;
    if(!gate) return '';
    const label = gate.type === 'final' ? 'Final Boss' : `Boss Gate ${gate.gate}`;
    const first = gate.after?.[0] || sid - 2;
    const last = gate.after?.[gate.after.length-1] || sid;
    return `<div class="compact-checkpoint-note"><b>Checkpoint after this group:</b> Pass S${safe(first)}–S${safe(last)} to unlock ${safe(label)}.<span>S${safe(sid)} is still a normal Session.</span></div>`;
  }


  function unifiedCheckpointSessionPage(sessionId, reason){
    const sid = Number(sessionId || state.currentSession || 1) || 1;
    const s = safeSessionMeta ? safeSessionMeta(sid) : (typeof getSession === 'function' ? getSession(sid) : {id:sid,title:`Session ${sid}`});
    const path = (typeof skillPathForSession === 'function') ? skillPathForSession(sid) : {core:'Reading', support:'Writing'};
    const visibleSkills = (typeof isSimpleMode === 'function' && isSimpleMode())
      ? [path.core].concat((typeof featureUnlocked === 'function' && featureUnlocked('supportMission')) ? [path.support] : [])
      : ['Reading','Writing','Listening','Speaking'];
    const cards = visibleSkills.map(skill=>{
      const required = skill === path.core ? 'Core' : skill === path.support ? 'Support' : 'Optional';
      let done = false;
      try{ done = typeof portfolioEvidence === 'function' && portfolioEvidence(sid, skill).length > 0; }catch(e){}
      return `<div class="hud-card ${done?'ok':''}">
        <h3>${done?'✅':'⬜'} ${safe(skill)}</h3>
        <p class="mini-note">${safe(required)} Mission</p>
        ${typeof sessionQualityHTML === 'function' ? sessionQualityHTML(sid) : ''}
        <button class="btn primary full" onclick="return EAPHero.openSkillMissionSafe('${safe(skill)}',${sid})">Start ${safe(skill)}</button>
      </div>`;
    }).join('');
    layout(`<section class="panel skill-path-panel normalized-checkpoint-session" style="margin-top:20px">
      <h2>Session ${sid}: ${safe(s.title || s.name || 'Academic English Mission')}</h2>
      <p class="lead">${safe(s.skill || s.subtitle || 'Academic English practice')}</p>
      <div class="route-note normal-route-note">Flow: Map → Individual Core/Support Mission → Mini Check → Map</div>
      ${selfPracticeCoreHTML(sid)}
      ${visibleSessionCompletionBadgeHTML(sid)}
      <div class="grid four">${cards}</div>
      <div class="simple-mode-note">Simple Mode: ตอนนี้ให้ทำ Core Mission ก่อน และ Support Mission ได้แล้ว</div>
      ${compactCheckpointNoteHTML(sid)}
      <div class="footer-actions">
        <button class="btn" onclick="EAPHero.map()">Map</button>
        <button class="btn ghost" onclick="return EAPHero.openSkillMissionSafe('Reading',${sid})">Debug: Open Reading</button>
      </div>
    </section>`);
    return false;
  }


  function simpleSessionFallback(sessionId, err){
    const sid = Number(sessionId || state.currentSession || 1) || 1;
    if([3,6,9,12,15].includes(sid)){
      return unifiedCheckpointSessionPage(sid, err);
    }
    const s = safeSessionMeta(sid);
    const gateNote = '';
    layout(`<section class="panel simple-session-fallback" style="margin-top:20px">
      <div class="badges"><span class="pill">Safe Session Mode</span><span class="pill">S${sid}</span><span class="pill">v1z50</span></div>
      <h2>Session ${sid}: ${safe(s.title || s.name || 'Academic English Mission')}</h2>
      <p class="lead">${safe(s.subtitle || s.skill || 'Practice individual Reading, Writing, Listening, and Speaking missions.')}</p>
      ${gateNote}
      <div class="grid four skill-open-grid">
        <button class="btn primary" onclick="return EAPHero.openSkillMissionSafe('Reading',${sid})">Reading</button>
        <button class="btn primary" onclick="return EAPHero.openSkillMissionSafe('Writing',${sid})">Writing</button>
        <button class="btn primary" onclick="return EAPHero.openSkillMissionSafe('Listening',${sid})">Listening</button>
        <button class="btn primary" onclick="return EAPHero.openSkillMissionSafe('Speaking',${sid})">Speaking</button>
      </div>
      <div class="footer-actions">
        <button class="btn" onclick="EAPHero.map()">Back to Map</button>
        <button class="btn ghost" onclick="EAPHero.renderStudentReports()">My Learning Report</button>
      </div>
      ${err ? `<div class="soft-recovery-note">Checkpoint note: ${safe(err.message || err)}</div>` : ''}
    </section>`);
    return false;
  }

  function openSkillMissionSafe(skill, sessionId){
    const sid = Number(sessionId || state.currentSession || 1) || 1;
    try{
      state.currentSession = sid;
      saveState();
      if(typeof openSkillMission === 'function'){
        openSkillMission(skill, sid);
      }else if(skill === 'Reading' && typeof renderReadingMission === 'function') renderReadingMission(sid);
      else if(skill === 'Writing' && typeof renderWritingMission === 'function') renderWritingMission(sid);
      else if(skill === 'Listening' && typeof renderListeningMission === 'function') renderListeningMission(sid);
      else if(skill === 'Speaking' && typeof renderSpeakingMission === 'function') renderSpeakingMission(sid);
      else simpleSessionFallback(sid, 'Mission renderer not found');
    }catch(err){
      console.error('[openSkillMissionSafe]', err);
      try{ logRuntimeErrorSafe('openSkillMissionSafe', err, {skill, sessionId:sid}); }catch(e){}
      renderSessionRecoveryPanel(sid, err, 'openSkillMissionSafe');
    }
    return false;
  }


  function testS3S6Open(){
    return {
      s3: typeof directOpenSession === 'function',
      s6: typeof simpleSessionFallback === 'function',
      skillSafe: typeof openSkillMissionSafe === 'function'
    };
  }



  function checkpointSessionIdFromElement(el){
    if(!el || !el.closest) return 0;
    const node = el.closest('[data-session], [data-sid], .map-card, .session-card, .card');
    if(!node) return 0;
    const attrs = [node.getAttribute('data-session'), node.getAttribute('data-sid'), node.dataset?.session, node.dataset?.sid];
    for(const a of attrs){ const n = Number(a || 0); if([3,6,9,12,15].includes(n)) return n; }
    const txt = (node.textContent || '').replace(/\s+/g,' ');
    const m = txt.match(/\bSESSION\s*(3|6|9|12|15)\b|\bS(3|6|9|12|15)\b/i);
    if(m) return Number(m[1] || m[2] || 0);
    const onclick = String(node.getAttribute('onclick') || '');
    const om = onclick.match(/\((3|6|9|12|15)\)/);
    if(om) return Number(om[1]);
    return 0;
  }

  function forceCheckpointSessionFallback(sessionId, reason){
    const sid = Number(sessionId || state.currentSession || 1) || 1;
    state.currentSession = sid;
    saveState();
    return unifiedCheckpointSessionPage(sid, reason || 'Checkpoint session opened with unified safe UI.');
  }

  function bindCheckpointSessionIntercept(){
    if(window.__EAP_CHECKPOINT_SESSION_INTERCEPT__) return;
    window.__EAP_CHECKPOINT_SESSION_INTERCEPT__ = true;
    document.addEventListener('click', function(ev){
      if(ev.target.closest && ev.target.closest('.simple-session-fallback,.black-screen-recovery,.boss-timeline,.topbar')) return;
      const sid = checkpointSessionIdFromElement(ev.target);
      if(!sid) return;
      ev.preventDefault();
      ev.stopPropagation();
      ev.stopImmediatePropagation();
      forceCheckpointSessionFallback(sid, 'Opened by v1z49 hard intercept to prevent black screen.');
    }, true);
  }

  function patchCheckpointSessionCards(){
    try{
      document.querySelectorAll('.map-card,.session-card,.card,[data-session],[data-sid]').forEach(card=>{
        const sid = checkpointSessionIdFromElement(card);
        if(!sid) return;
        card.setAttribute('data-checkpoint-session', String(sid));
        card.setAttribute('onclick', `return EAPHero.forceCheckpointSessionFallback(${sid}, 'Opened by patched card handler')`);
        card.classList.add('checkpoint-session-safe-card');
      });
    }catch(err){ console.warn('[patchCheckpointSessionCards]', err); }
  }

  function runCheckpointSessionPatchSoon(){
    bindCheckpointSessionIntercept();
    patchCheckpointSessionCards();
    setTimeout(patchCheckpointSessionCards, 50);
    setTimeout(patchCheckpointSessionCards, 250);
    setTimeout(patchCheckpointSessionCards, 800);
  }

