  function renderSkillPath(sessionId){
    setTimeout(()=>attachSafeBossGateNotice(Number(arguments[0] || state.currentSession || 1)), 120);
    try{
      setTimeout(runBossGateUICleanupSoon, 0);

      const s = getSession(Number(sessionId || 1));
      const path = skillPathForSession(s.id);
      const gate = bossGateForSession(s.id);
      const studentFlow = isStudentCourseFlow();
      const visibleSkills = Array.from(new Set([path.core, path.support].filter(Boolean)));
      const passReport = sessionPassReport(s.id);
      const skillRows = passReport.skillRows || [];
      const completedSkills = skillRows.filter(row=>row.passed).length;
      const totalSkills = visibleSkills.length || 2;
      const passMark = Number(PASS_RULES?.sessionMinScore || 60);
      const cards = visibleSkills.map(skill=>{
        const role = skill === path.core ? 'Core' : 'Support';
        const best = bestScoreForSessionSkill(s.id, skill);
        return sessionMissionCardSummaryHTML(s.id, skill, role, best >= passMark);
      }).join('');

      layout(`
        <section class="panel session-path-panel" style="margin-top:20px">
          <div class="badges">
            <span class="pill">Self-Practice Path</span>
            <span class="pill">S${s.id}</span>
            <span class="pill">${safe(s.skill)}</span>
            <span class="pill">Core + Support</span>
          </div>
          <h2>Session ${s.id}: ${safe(s.title || s.skill)}</h2>
          <p class="lead">ฝึกด้วยตนเองให้ครบทั้ง Core และ Support Mission โดยแต่ละรอบจะได้ Gold Source และโจทย์ตามระดับ AI ของทักษะนั้น</p>
          <div class="session-path-rule">
            <div><b>Pass progress: ${completedSkills}/${totalSkills} skill${totalSkills===1?'':'s'} complete</b><span>ผ่านเมื่อแต่ละทักษะได้ ${passMark}% ขึ้นไป</span></div>
            <div class="session-pass-skills">${skillRows.map(row=>`<span class="${row.passed?'passed':'pending'}">${row.passed?'✅':'⬜'} ${safe(row.skill)} ${row.bestScore ? `${row.bestScore}/100` : 'not started'}</span>`).join('')}</div>
          </div>
          <div class="session-self-practice-mini">
            <b>👤 Self-practice only</b>
            <span>คะแนนและการปลด Session มาจากผลงานในเกมของผู้เรียน กิจกรรมสดในห้องเรียนไม่ใช่เงื่อนไขผ่านด่าน</span>
          </div>
          <div class="grid two session-path-missions">${cards}</div>
          ${gate ? `<div class="session-checkpoint-card">
            <b>🏁 Checkpoint after this Session group</b>
            <span>${safe(gate.title || gate.boss || 'Boss Gate')} · ${bossGateStatus(gate) ? '✅ Ready to open' : '🔒 Complete the required Sessions first'}</span>
          </div>` : ''}
          <div class="footer-actions session-path-actions">
            <button class="btn" onclick="EAPHero.map()">🗺️ Back to Map</button>
            <button class="btn" onclick="EAPHero.renderStudentReports()">📘 My Learning Report</button>
            ${studentFlow ? '' : `<button class="btn ghost" onclick="EAPHero.skillHub(${s.id})">Four Skills Hub</button><button class="btn ghost small" onclick="return EAPHero.openSkillMission('Reading', ${s.id})">Debug: Open Reading</button>`}
          </div>
        </section>
      `);
    }catch(err){
      console.error('[renderSkillPath]', err);
      logRuntimeErrorSafe('renderSkillPath', err, {sessionId:(typeof sessionId!=='undefined'?sessionId:state.currentSession||1)});
      renderSessionRecoveryPanel((typeof sessionId!=='undefined'?sessionId:state.currentSession||1), err, 'renderSkillPath');
    }
  }
  function renderBossGate(gateId){
    const requested = String(gateId || '');
    const gateNo = Number(requested) || bossGateNumberFromId(requested) || 1;
    const gate = BOSS_GATES.find(g => g.id === requested || Number(g.gate) === gateNo || Number(g.after) === gateNo) || BOSS_GATES[0];
    const unlocked = bossGateStatus(gate);
    const mutation = mutationForGate(gate.id);
    const ghost = state.replay?.ghosts?.[gate.id];
    layout(`
      <section class="panel" style="margin-top:20px">
        <div class="badges"><span class="pill">Boss Gate</span><span class="pill">${safe(gate.title)}</span><span class="pill">${unlocked?'Unlocked':'Locked'}</span></div>
        <h2>${safe(gate.boss)}</h2>
        <p class="lead">${safe(gate.unlock)}</p>
        <div class="grid three">
          <div class="stat"><b>${safe(mutation.name)}</b><span>Mutation</span></div>
          <div class="stat"><b>${ghost ? ghost.bestPercent+'%' : '-'}</b><span>Rival Ghost</span></div>
          <div class="stat"><b>${gate.skills.join(' + ')}</b><span>Skill Check</span></div>
        </div>
        <div class="panel light" style="margin-top:18px">
          <h3>Boss Rule</h3>
          <p class="mini-note">บอสช่วงนี้ใช้ MCQ + Reason Gate + portfolio evidence ร่วมกัน ไม่ใช่เลือกตอบอย่างเดียว</p>
        </div>
        <div class="footer-actions">
          <button class="btn primary" ${(unlocked && featureUnlocked('bossGate'))?'':'disabled'} onclick="EAPHero.startGateBoss('${gate.id}')">${featureUnlocked('bossGate')?'Start Gate Boss':'Boss Gate unlocks later'}</button>
          <button class="btn" onclick="return EAPHero.directOpenSession(${gate.after})">Complete Skill Evidence</button>
          <button class="btn ghost" onclick="EAPHero.replayHub()">Replay Hub</button>
        </div>
      </section>`);
  }

  function mutationForGate(gateId){
    const logs = (state.replay?.bossRushLogs || []).filter(x => x.gateId === gateId).length;
    return MUTATIONS[logs % MUTATIONS.length];
  }

  function startGateBoss(gateId){
    const gate = BOSS_GATES.find(g => g.id === gateId);
    if(!gate || !bossGateStatus(gate)) return renderBossGate(gateId);
    const mutation = mutationForGate(gateId);
    state.replay.currentGate = gateId;
    state.replay.currentMutation = mutation.key;
    saveState();
    startBoss(gate.after, mutation.key === 'nohint' ? 'nohint' : mutation.key === 'speed' ? 'speed' : 'hero');
  }

  function updateMasteryFromPortfolio(entry){
    if(!entry || !entry.skill) return;
    state.mastery = state.mastery || {};
    const skill = entry.skill;
    state.mastery[skill] = Math.min(100, (state.mastery[skill] || 0) + Math.max(3, Math.round((entry.score || 0)/20)));
    if(Number(entry.session) === 12) state.mastery.Ethics = Math.min(100, (state.mastery.Ethics || 0) + 4);
  }

  function masteryRank(score){
    if(score >= 90) return 'S';
    if(score >= 75) return 'A';
    if(score >= 60) return 'B';
    if(score >= 40) return 'C';
    if(score >= 20) return 'D';
    return 'E';
  }

  function renderReplayHub(){
    const gates = BOSS_GATES.map(g=>{
      const unlocked = bossGateStatus(g);
      const ghost = state.replay?.ghosts?.[g.id];
      return `<div class="hud-card">
        <h3>${safe(g.title)}</h3>
        <p>${safe(g.boss)}</p>
        <p class="mini-note">${unlocked?'✅ Unlocked':'🔒 '+g.unlock}</p>
        <p class="mini-note">Ghost: ${ghost ? ghost.bestPercent+'% / combo '+ghost.bestCombo : '-'}</p>
        <button class="btn ${unlocked?'primary':'ghost'} block" onclick="EAPHero.bossGate('${g.id}')">${unlocked?'Challenge':'View Gate'}</button>
      </div>`;
    }).join('');
    const mastery = ['Reading','Writing','Listening','Speaking','Ethics'].map(k=>`<div class="stat"><b>${masteryRank(state.mastery?.[k]||0)}</b><span>${k} ${state.mastery?.[k]||0}</span></div>`).join('');
    layout(`
      <section class="panel" style="margin-top:20px">
        <div class="badges"><span class="pill">Replay Challenge Layer</span><span class="pill">Boss Mutation</span><span class="pill">Rival Ghost</span></div>
        <h2>Replay Hub</h2>
        <p class="lead">เล่นซ้ำเพื่อชนะตัวเอง เก็บ mastery rank ปลด secret missions และท้าทาย boss mutation</p>
        <h3>Skill Mastery</h3><div class="grid five">${mastery}</div>
        <h3 style="margin-top:20px">Boss Gates</h3><div class="grid three">${gates}</div>
        <div class="panel light" style="margin-top:18px"><h3>Secret Missions</h3>${secretMissionRows()}</div>
      </section>`);
  }

  function secretMissionRows(){
    const missions = [
      ['no_hint_win','Win any Boss Gate with No Hint Form'],
      ['reason_chain','Answer 5 Reason Gates correctly'],
      ['portfolio_10','Collect 10 portfolio evidence items'],
      ['skill_balance','Reach rank C in all four skills'],
      ['ghost_beater','Beat your Rival Ghost once']
    ];
    return `<div class="grid three">${missions.map(m=>`<div class="hud-card"><h3>${state.replay?.secretMissions?.[m[0]]?'🏆':'🔒'} ${safe(m[0])}</h3><p class="mini-note">${safe(m[1])}</p></div>`).join('')}</div>`;
  }

  function checkSecretMissions(){
    state.replay = state.replay || {secretMissions:{}};
    const sm = state.replay.secretMissions = state.replay.secretMissions || {};
    if((state.portfolio || []).length >= 10) sm.portfolio_10 = true;
    if(['Reading','Writing','Listening','Speaking'].every(k => (state.mastery?.[k] || 0) >= 40)) sm.skill_balance = true;
  }



  const AI_LIMITS = {
    perSession: 2,
    perDay: 8,
    examAllowed: false,
    bossAllowed: false
  };

  function todayKey(){
    return new Date().toISOString().slice(0,10);
  }

  function aiUseKey(sessionId, skill){
    return `S${sessionId}_${skill}`;
  }

  function aiUsesFor(sessionId, skill){
    state.ai = state.ai || {dailyUses:{}, logs:[], sessionUses:{}};
    const key = aiUseKey(sessionId, skill);
    return state.ai.sessionUses[key] || 0;
  }

  function aiDailyUses(){
    state.ai = state.ai || {dailyUses:{}, logs:[], sessionUses:{}};
    return state.ai.dailyUses[todayKey()] || 0;
  }

    function canUseAI(sessionId, skill){
    const dkey = todayKey();
    state.ai = state.ai || {dailyUses:{}, logs:[], sessionUses:{}};
    const daily = state.ai.dailyUses[dkey] || 0;
    const key = aiUseKey(sessionId, skill);
    const used = state.ai.sessionUses[key] || 0;
    const limit = adaptiveAIHelpLimit(skill);
    const dailyLimit = AI_LIMITS.daily || 8;
    if(used >= limit) return {ok:false, reason:`AI Help limit reached for this ${skill} mission.`, used, limit, daily, dailyLimit};
    if(daily >= dailyLimit) return {ok:false, reason:`Daily AI Help limit reached (${dailyLimit}/day).`, used, limit, daily, dailyLimit};
    return {ok:true, used, limit, daily, dailyLimit};
  }
  function aiDraftInputId(skill){
    if(skill === 'Reading') return 'readAns0';
    if(skill === 'Writing') return 'writingOut';
    if(skill === 'Listening') return 'listeningNotes';
    if(skill === 'Speaking') return 'speakingTranscript';
    return '';
  }

  function aiOutputId(skill, sessionId){
    return `aiHelpOutput_${String(skill || 'Skill')}_${Number(sessionId || 0)}`;
  }

  function collectAIDraft(skill){
    if(skill === 'Reading'){
      return [0,1,2].map(i => document.getElementById('readAns'+i)?.value || '').join(' ').trim();
    }
    const id = aiDraftInputId(skill);
    return (document.getElementById(id)?.value || '').trim();
  }

  function analyzeDraftForAI(skill, draft){
    const text = String(draft || '').trim();
    const words = text ? text.split(/\s+/).filter(Boolean) : [];
    const lower = text.toLowerCase();
    const hasEvidence = /\b(evidence|example|data|source|because|for example|for instance|shows|suggests|indicates)\b/i.test(text);
    const hasAcademicTone = /\b(may|might|suggests|indicates|appears|can|could|therefore|however|although)\b/i.test(text);
    const hasStructure = /\b(first|second|next|finally|in conclusion|therefore|however|because|one reason|this means)\b/i.test(text);
    const hasQuestion = /\?/.test(text);
    const notes = [];

    if(words.length === 0){
      notes.push('You have not written a draft yet. Use the frame to start, then add your own content.');
    } else {
      if(skill === 'Reading'){
        if(words.length < 18) notes.push('Your reading answer is still short. Add the main idea, two keywords, and one supporting detail.');
        if(!hasEvidence) notes.push('Add one phrase or detail from the passage as evidence.');
        if(!/\bmain|idea|purpose|claim|keyword|support/i.test(text)) notes.push('Name the reading focus clearly: main idea, purpose, claim, keyword, or support.');
      }
      if(skill === 'Writing'){
        if(words.length < 45) notes.push('Your writing draft needs more development. Add a topic sentence, support, and conclusion.');
        if(!hasEvidence) notes.push('Add evidence, an example, or a reason to support your claim.');
        if(!hasAcademicTone) notes.push('Make the tone more academic by using cautious words such as suggests, may, or indicates.');
        if(!hasStructure) notes.push('Add transitions such as first, however, therefore, or in conclusion.');
      }
      if(skill === 'Listening'){
        if(words.length < 25) notes.push('Your notes are short. Add main point, keywords, evidence/example, and one question.');
        if(!hasStructure) notes.push('Organize your notes with labels such as Main point, Evidence, Signal words, Question.');
        if(!hasQuestion) notes.push('Add one follow-up question after listening.');
      }
      if(skill === 'Speaking'){
        if(words.length < 45) notes.push('Your speaking notes/transcript are short. Add opening, evidence, and closing.');
        if(!hasStructure) notes.push('Add signposting such as Today I will explain, First, Next, In conclusion.');
        if(!hasEvidence) notes.push('Add one supporting reason, example, or evidence.');
      }
    }

    if(!notes.length) notes.push('Your draft has a clear start. Improve it by adding one more precise academic detail and checking clarity.');
    return { wordCount:words.length, notes:notes.slice(0,3), hasEvidence, hasAcademicTone, hasStructure };
  }


  function aiMentorMessage(skill, sessionId, draftText){
    const s = getSession(Number(sessionId || 1));
    const topic = skillTextForSession(s).topic;
    const nextUse = aiUsesFor(sessionId, skill) + 1;
    const draftInfo = analyzeDraftForAI(skill, draftText || '');
    const alignedHelp = alignedAIHelpMessage(skill, sessionId, draftText || '', nextUse, draftInfo);
    if(alignedHelp) return alignedHelp;

    const level1 = {
      Reading:[
        `Look for the sentence that covers the whole passage about ${topic}, not only one detail.`,
        'Try to separate the main idea from examples, names, and numbers.',
        'Check repeated keywords and the first or final sentence.'
      ],
      Writing:[
        `Plan first: topic sentence → support/evidence → concluding sentence about ${topic}.`,
        'Use cautious academic language such as may, suggests, indicates, can support.',
        'Do not copy the prompt. Rewrite the idea in your own words and keep the meaning.'
      ],
      Listening:[
        `Before listening, predict keywords about ${topic}.`,
        'Write short notes, not full sentences: main point, signal words, evidence.',
        'Listen for first, next, however, therefore, in conclusion.'
      ],
      Speaking:[
        `Use this structure: opening → outline → evidence → conclusion about ${topic}.`,
        'Start with a short opening, then give one clear reason.',
        'Add signposting: First, ... Next, ... In conclusion, ...'
      ]
    };

    const level2 = {
      Reading:[
        `Use this answer frame: The passage mainly explains that ___. Two keywords are ___ and ___. A useful supporting detail is ___.`,
        `Check your answer: Does it cover the whole topic of ${topic}, or only one small detail?`,
        'Try this frame: The writer’s purpose is to ___ because the passage emphasizes ___.'
      ],
      Writing:[
        `Try this frame: This topic is important because ___. One reason is ___. This suggests that ___.`,
        `For academic tone, write: The text suggests that ___. I need more information about ___.`,
        `For a paragraph, use: Topic sentence → For example/One reason → This means that → Therefore/In conclusion.`
      ],
      Listening:[
        `Use this note frame: Main point: ___. Keywords: ___ / ___ / ___. Evidence/example: ___. Question: ___.`,
        `After listening, complete: The speaker first explains ___. Then, the speaker gives ___. The conclusion is ___.`,
        'If you missed details, write the relationship instead: cause → effect, problem → solution, claim → evidence.'
      ],
      Speaking:[
        `Use this speaking frame: Today, I will explain ___. First, ___. For example, ___. In conclusion, ___.`,
        `For Q&A, try: Thank you for the question. My answer is ___. The reason is ___.`,
        `For evidence talk, say: My idea is ___. One example is ___. This is important because ___.`
      ]
    };

    const selected = nextUse >= 2 ? level2 : level1;
    const arr = selected[skill] || ['Think about the target skill and explain your answer clearly.'];
    let baseMsg = arr[(nextUse - 1) % arr.length];
    if(nextUse >= 2){
      baseMsg = `Draft check (${draftInfo.wordCount} words): ${draftInfo.notes.join(' ')} Frame: ${baseMsg}`;
    }
    return {
      level: nextUse >= 2 ? 'draft-aware-response-frame' : 'strategy-hint',
      message: baseMsg,
      useNumber: nextUse,
      draftWordCount:draftInfo.wordCount,
      draftNotes:draftInfo.notes
    };
  }

  
  function aiHelpRuntimeState(skill, sessionId){
    const limit = aiLimitFor(skill, sessionId);
    const used = aiUsesFor(skill, sessionId);
    const left = Math.max(0, Number(limit || 0) - Number(used || 0));
    return {limit, used, left, allowed:left > 0};
  }

  function repairAIHelpBoxes(){
    document.querySelectorAll('[id^="aiOut"], .ai-output, .ai-help-output').forEach(el=>{
      const txt = (el.textContent || '').trim();
      if(/limit reached/i.test(txt)){
        const near = el.closest('.panel,.card,.ai-box,section,div') || document;
        const leftText = (near.textContent || '').match(/(\d+)\/(\d+)\s*left/i);
        if(leftText && Number(leftText[1]) > 0){
          el.textContent = 'AI Mentor is ready. Click Ask AI Mentor to get a hint.';
          el.classList.add('ai-ready-text');
        }
      }
    });
  }

  function runAIHelpRepairSoon(){
    repairAIHelpBoxes();
    setTimeout(repairAIHelpBoxes, 0);
    setTimeout(repairAIHelpBoxes, 120);
  }


  function renderAIHelpBox(skill, sessionId){
    sessionId = Number(sessionId || 1);
    if(typeof independenceReplayActive === 'function' && independenceReplayActive(sessionId, skill)){
      return `<div class="independence-replay-banner compact-replay">
        <b>🛡 Independent Replay active</b>
        <span>AI Help is paused for this attempt so your independent evidence can be checked.</span>
      </div>`;
    }
    const uses = aiUsesFor(sessionId, skill);
    const limit = adaptiveAIHelpLimit(skill);
    const left = Math.max(0, limit - uses);
    const draftId = skill === 'Reading' ? 'readingAns0'
      : skill === 'Writing' ? 'writingOutput'
      : skill === 'Listening' ? 'listeningNotes'
      : skill === 'Speaking' ? 'speakingTranscript'
      : '';
    const outputId = aiOutputId(skill, sessionId);
    const stage = uses < limit ? aiHelpStageLabel(uses + 1, limit) : 'Limit reached';
    const goldTask = currentGoldTaskContext(skill, sessionId);
    const goldLabel = goldTask?.gold ? ` · ${goldTask.sourceId || 'Gold Source'}` : '';
    const intro = goldTask?.gold
      ? 'Open only when you need a source-specific hint. AI will not provide the answer.'
      : 'Open only when you need a hint, frame, or self-check.';
    return `<details class="ai-help-drawer">
      <summary>🤖 AI Mentor · ${left}/${limit} hints left · ${safe(stage)}${safe(goldLabel)}</summary>
      <div class="ai-help-drawer-body">
        <p>${safe(intro)}</p>
        <button type="button" class="btn ai-mentor-btn" ${left<=0?'disabled':''} onclick="EAPHero.aiHelp('${safeAttr(skill)}', ${sessionId}, '${draftId}', '${outputId}')">${safe(aiHelpButtonLabel(skill, sessionId))}</button>
        <div id="${outputId}" class="feedback info ai-output-box" style="margin-top:10px;display:none"></div>
      </div>
    </details>`;
  }
  function useAIHelp(skill, sessionId, draftInputId, outputId){
    if(typeof independenceReplayActive === 'function' && independenceReplayActive(sessionId, skill)){
      const out = document.getElementById(outputId || aiOutputId(skill, sessionId)) || document.getElementById('aiHelpOutput');
      const message = 'Independent Replay is active. AI Help is paused for this attempt so your own evidence can be checked.';
      if(out){
        out.style.display = 'block';
        out.classList.add('show');
        out.innerHTML = `<b>AI Mentor:</b> ${safe(message)}`;
      }else safeToast(message);
      return;
    }
    const allowed = canUseAI(sessionId, skill);
    const out = document.getElementById(outputId || aiOutputId(skill, sessionId)) || document.getElementById('aiHelpOutput');
    if(!allowed.ok){
      if(out){
        out.style.display = 'block';
        out.classList.add('show');
        out.innerHTML = `<b>AI Mentor:</b> ${safe(allowed.reason)}`;
      }else alert(allowed.reason);
      return;
    }
    state.ai = state.ai || {dailyUses:{}, logs:[], sessionUses:{}};
    const key = aiUseKey(sessionId, skill);
    state.ai.sessionUses[key] = (state.ai.sessionUses[key] || 0) + 1;
    state.ai.dailyUses[todayKey()] = (state.ai.dailyUses[todayKey()] || 0) + 1;
    const draftText = draftInputId ? (document.getElementById(draftInputId)?.value || collectAIDraft(skill)) : collectAIDraft(skill);
    const ai = aiMentorMessage(skill, sessionId, draftText);
    const msg = ai.message || String(ai);
    state.ai.logs.push({
      session:Number(sessionId),
      skill,
      helpLevel:ai.level || 'strategy-hint',
      draftWordCount:ai.draftWordCount || 0,
      draftNotes:(ai.draftNotes || []).join(' | '),
      message:msg,
      useNumber:state.ai.sessionUses[key],
      day:todayKey(),
      at:new Date().toISOString(),
      student_id:state.profile.studentId || 'guest'
    });
    state.ai.logs = state.ai.logs.slice(-100);
    saveState();
    if(out){
      out.classList.add('show');
      out.style.display = 'block';
      out.innerHTML = `<div class="ai-output-title">🤖 AI Mentor (${safe(ai.level || 'hint')})</div>
        <div class="ai-output-message">${safe(msg)}</div>
        <div class="mini-note">Uses left: ${Math.max(0, adaptiveAIHelpLimit(skill) - state.ai.sessionUses[key])} • ครั้งที่ 2 จะตรวจ draft/notes/transcript ที่พิมพ์อยู่ แล้วให้กรอบปรับแก้ แต่ยังไม่เฉลย</div>`;
    }else{
      alert(`AI Mentor: ${msg}`);
    }
  }

  function aiPenaltyForPortfolio(sessionId, skill){
    return aiPenaltyForSkillLevel(skill, sessionId);
  }

  function exportAIHelpCSV(){
    const header = ['student_id','session','skill','useNumber','helpLevel','draftWordCount','draftNotes','message','day','at'];
    const rows = (state.ai?.logs || []).map(r => header.map(h => csvCell(r[h])).join(','));
    const csv = [header.join(','), ...rows].join('\n');
    const blob = new Blob([csv], {type:'text/csv;charset=utf-8'});
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'eap-hero-ai-help-logs.csv';
    a.click();
    URL.revokeObjectURL(url);
  }



